// 1. Sadə Generic Interfeys
interface Box<T> {
  content: T;
  id: string;
}
const stringBox: Box<string> = { content: "Book", id: "B001" };
const numberBox: Box<number> = { content: 100, id: "B002" };
console.log(stringBox); // Çıxış: { content: "Book", id: "B001" }
console.log(numberBox); // Çıxış: { content: 100, id: "B002" }

// 2. Generic ilə məhdudiyyətlər
interface Lengthy<T extends { length: number }> {
  item: T;
  getLength(): number;
}
const stringLength: Lengthy<string> = {
  item: "Test",
  getLength() { return this.item.length; }
};
console.log(stringLength.getLength()); // Çıxış: 4
// const numberLength: Lengthy<number> = { item: 42, getLength() { return this.item.length; } }; // Səhv: number-ın length xüsusiyyəti yoxdur

// 3. Çoxsaylı Generic tiplər
interface Pair<K, V> {
  key: K;
  value: V;
}
const pair: Pair<string, number> = { key: "Age", value: 25 };
console.log(pair); // Çıxış: { key: "Age", value: 25 }

// 4. Default Generic tiplər
interface Wrapper<T = string> {
  value: T;
}
const stringWrapper: Wrapper = { value: "Test" }; // T avtomatik string olur
const numberWrapper: Wrapper<number> = { value: 42 };
console.log(stringWrapper); // Çıxış: { value: "Test" }
console.log(numberWrapper); // Çıxış: { value: 42 }

// 5. Generic ilə union tipləri
type AllowedType = string | number;
interface Restricted<T extends AllowedType> {
  data: T;
}
const stringData: Restricted<string> = { data: "Hello" };
const numberData: Restricted<number> = { data: 123 };
console.log(stringData); // Çıxış: { data: "Hello" }
console.log(numberData); // Çıxış: { data: 123 }
// const boolData: Restricted<boolean> = { data: true }; // Səhv: boolean AllowedType-a uyğun deyil

// 6. Generic Interfeys ilə siniflər
interface Item<T> {
  id: string;
  data: T;
}
class Product<T> implements Item<T> {
  id: string;
  data: T;
  constructor(id: string, data: T) {
    this.id = id;
    this.data = data;
  }
  getDetails(): string {
    return `ID: ${this.id}, Data: ${this.data}`;
  }
}
const laptop = new Product<string>("P001", "Laptop");
console.log(laptop.getDetails()); // Çıxış: ID: P001, Data: Laptop

// 7. Generic Interfeys ilə funksiyalar
function processItem<T>(item: Item<T>): string {
  return `Item ID: ${item.id}, Data: ${item.data}`;
}
const item: Item<number> = { id: "I001", data: 999 };
console.log(processItem(item)); // Çıxış: Item ID: I001, Data: 999

// Sadə mağaza sistemi
interface Product<T> {
  id: string;
  data: T;
}
class ProductStore<T> {
  products: Product<T>[] = [];
  add(product: Product<T>): void {
    this.products.push(product);
  }
  getById(id: string): Product<T> | undefined {
    return this.products.find(p => p.id === id);
  }
}
const store = new ProductStore<string>();
const laptop: Product<string> = { id: "P001", data: "Laptop" };
store.add(laptop);
store.add({ id: "P002", data: "Mouse" });
console.log(store.getById("P001")); // Çıxış: { id: "P001", data: "Laptop" }

const numberStore = new ProductStore<number>();
const price: Product<number> = { id: "P003", data: 999 };
numberStore.add(price);
console.log(numberStore.getById("P003")); // Çıxış: { id: "P003", data: 999 }

// Generic interfeys ilə funksiya
function checkProduct<T>(product: Product<T>): string {
  return `Product ID: ${product.id}, Data: ${product.data}`;
}
console.log(checkProduct(laptop)); // Çıxış: Product ID: P001, Data: Laptop

